import React, { useState, useEffect } from 'react';
import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
import { 
  Calendar, 
  Plus, 
  Edit3, 
  Trash2, 
  Download, 
  Copy, 
  Move, 
  ChevronLeft, 
  ChevronRight,
  Save,
  X,
  RefreshCw,
  FileImage,
  FileSpreadsheet
} from 'lucide-react';
import { useClient } from '../contexts/ClientContext';
import roadmapApi from '../api/roadmap';

// Types
interface Asset {
  id: string;
  title: string;
  dueDate: string;
  channel: string;
  funnelStage: FunnelStage;
  campaign: string;
  description?: string;
  startDate: string;
  createdAt: string;
  updatedAt: string;
}

type FunnelStage = 'awareness' | 'interest' | 'consideration' | 'download' | 'registration' | 'conversion' | 'retention';

interface Period {
  id: string;
  name: string;
  startDate: string;
  endDate: string;
}

interface Campaign {
  id: string;
  name: string;
  color: string;
}

// Constants
const FUNNEL_STAGES = [
  { id: 'awareness', name: 'Awareness', color: '#E3F2FD', darkColor: '#1976D2' },
  { id: 'interest', name: 'Interest', color: '#E8F5E8', darkColor: '#388E3C' },
  { id: 'consideration', name: 'Consideration', color: '#FFF9C4', darkColor: '#F57F17' },
  { id: 'download', name: 'Download', color: '#FFE0B2', darkColor: '#F57C00' },
  { id: 'registration', name: 'Registration', color: '#F3E5F5', darkColor: '#7B1FA2' },
  { id: 'conversion', name: 'Conversion', color: '#FFEBEE', darkColor: '#D32F2F' },
  { id: 'retention', name: 'Retention', color: '#E8EAF6', darkColor: '#303F9F' }
];

const DEFAULT_PERIODS: Period[] = [
  { id: 'period1', name: 'NOVEMBER – MARCH', startDate: '2024-11-01', endDate: '2025-03-31' },
  { id: 'period2', name: 'APRIL – JUNE', startDate: '2025-04-01', endDate: '2025-06-30' }
];

const DEFAULT_CAMPAIGNS: Campaign[] = [
  { id: 'credit-card', name: 'Credit Card', color: '#1976D2' },
  { id: 'insurance', name: 'Insurance', color: '#388E3C' },
  { id: 'new-product', name: 'New Product', color: '#F57F17' }
];

const MONTHS = [
  'November', 'December', 'January', 'February', 'March',
  'April', 'May', 'June'
];

const RoadmapGenerator: React.FC = () => {
  const { selectedClient } = useClient();
  const [assets, setAssets] = useState<Asset[]>([]);
  const [periods] = useState<Period[]>(DEFAULT_PERIODS);
  const [campaigns] = useState<Campaign[]>(DEFAULT_CAMPAIGNS);
  const [selectedPeriod, setSelectedPeriod] = useState<string>(DEFAULT_PERIODS[0].id);
  const [currentMonth, setCurrentMonth] = useState<number>(0);
  const [editingAsset, setEditingAsset] = useState<Asset | null>(null);
  const [zoomLevel, setZoomLevel] = useState<number>(1);

  // Form state for asset creation/editing
  const [assetForm, setAssetForm] = useState({
    title: '',
    dueDate: '',
    channel: '',
    funnelStage: 'awareness' as FunnelStage,
    campaign: DEFAULT_CAMPAIGNS[0].id,
    description: '',
    startDate: ''
  });

  const queryClient = useQueryClient();

  // Fetch assets from API
  const { data: assetsData, isLoading: assetsLoading } = useQuery({
    queryKey: ['roadmap-assets', selectedClient?.id],
    queryFn: () => selectedClient ? roadmapApi.getAssets(selectedClient.id) : Promise.resolve({ assets: [] }),
    enabled: !!selectedClient,
  });

  // Update local state when API data changes
  useEffect(() => {
    if (assetsData?.assets) {
      setAssets(assetsData.assets);
    } else if (selectedClient && assets.length === 0) {
      // Initialize with sample data only if no data from API and client is selected
      const sampleAssets: Asset[] = [
        {
          id: '1',
          title: 'Credit Card Social Media Campaign',
          dueDate: '2024-11-15',
          channel: 'Instagram',
          funnelStage: 'awareness',
          campaign: 'credit-card',
          description: 'Launch awareness campaign for new credit card',
          startDate: '2024-11-01',
          createdAt: new Date().toISOString(),
          updatedAt: new Date().toISOString()
        },
        {
          id: '2',
          title: 'Insurance Email Series',
          dueDate: '2024-12-01',
          channel: 'Email',
          funnelStage: 'interest',
          campaign: 'insurance',
          description: 'Educational email series about insurance benefits',
          startDate: '2024-11-20',
          createdAt: new Date().toISOString(),
          updatedAt: new Date().toISOString()
        },
        {
          id: '3',
          title: 'Product Demo Video',
          dueDate: '2025-01-15',
          channel: 'YouTube',
          funnelStage: 'consideration',
          campaign: 'new-product',
          description: 'Detailed product demonstration video',
          startDate: '2025-01-01',
          createdAt: new Date().toISOString(),
          updatedAt: new Date().toISOString()
        },
        {
          id: '4',
          title: 'Download Landing Page',
          dueDate: '2025-02-01',
          channel: 'Website',
          funnelStage: 'download',
          campaign: 'credit-card',
          description: 'Landing page for credit card application download',
          startDate: '2025-01-20',
          createdAt: new Date().toISOString(),
          updatedAt: new Date().toISOString()
        },
        {
          id: '5',
          title: 'Registration Follow-up SMS',
          dueDate: '2025-03-01',
          channel: 'SMS',
          funnelStage: 'registration',
          campaign: 'insurance',
          description: 'Follow-up SMS for incomplete registrations',
          startDate: '2025-02-15',
          createdAt: new Date().toISOString(),
          updatedAt: new Date().toISOString()
        }
      ];
      setAssets(sampleAssets);
    }
  }, [assetsData, selectedClient, assets.length]);

  // Mock API calls - replace with actual API integration
  const fetchAssets = async (): Promise<Asset[]> => {
    // This would integrate with your CMS/media API
    return [];
  };

  const saveAsset = async (asset: Partial<Asset>): Promise<Asset> => {
    const newAsset: Asset = {
      id: Date.now().toString(),
      title: asset.title || '',
      dueDate: asset.dueDate || '',
      channel: asset.channel || '',
      funnelStage: asset.funnelStage || 'awareness',
      campaign: asset.campaign || DEFAULT_CAMPAIGNS[0].id,
      description: asset.description || '',
      startDate: asset.startDate || '',
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString()
    };
    return newAsset;
  };

  const updateAsset = async (id: string, updates: Partial<Asset>): Promise<Asset> => {
    const existingAsset = assets.find(a => a.id === id);
    if (!existingAsset) throw new Error('Asset not found');
    
    return {
      ...existingAsset,
      ...updates,
      updatedAt: new Date().toISOString()
    };
  };

  const deleteAsset = async (id: string): Promise<void> => {
    // API call to delete asset
  };

  // Mutations
  const updateAssetMutation = useMutation({
    mutationFn: ({ id, updates }: { id: string; updates: Partial<Asset> }) => 
      roadmapApi.createAsset({ assetId: id, ...updates }),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['roadmap-assets'] });
      setEditingAsset(null);
      resetAssetForm();
    }
  });

  const deleteAssetMutation = useMutation({
    mutationFn: roadmapApi.deleteAsset,
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['roadmap-assets'] });
    }
  });

  // Helper functions
  const resetAssetForm = () => {
    setAssetForm({
      title: '',
      dueDate: '',
      channel: '',
      funnelStage: 'awareness',
      campaign: DEFAULT_CAMPAIGNS[0].id,
      description: '',
      startDate: ''
    });
  };

  const handleFormSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    
    if (editingAsset) {
      updateAssetMutation.mutate({
        id: editingAsset.id,
        updates: {
          funnelStage: assetForm.funnelStage,
          startDate: assetForm.startDate,
          dueDate: assetForm.dueDate,
          campaign: assetForm.campaign
        }
      });
    }
  };

  const startEditingAsset = (asset: Asset) => {
    setEditingAsset(asset);
    setAssetForm({
      title: asset.title,
      dueDate: asset.dueDate,
      channel: asset.channel,
      funnelStage: asset.funnelStage,
      campaign: asset.campaign,
      description: asset.description || '',
      startDate: asset.startDate
    });
  };

  const getAssetsForStage = (stage: FunnelStage) => {
    return assets.filter(asset => asset.funnelStage === stage);
  };

  const getFunnelStageConfig = (stage: FunnelStage) => {
    return FUNNEL_STAGES.find(s => s.id === stage) || FUNNEL_STAGES[0];
  };

  const getCurrentPeriod = () => {
    return periods.find(p => p.id === selectedPeriod) || periods[0];
  };

  const getMonthsForPeriod = (period: Period) => {
    const start = new Date(period.startDate);
    const end = new Date(period.endDate);
    const months = [];
    
    const current = new Date(start);
    while (current <= end) {
      months.push({
        name: current.toLocaleString('default', { month: 'long' }),
        year: current.getFullYear(),
        date: new Date(current)
      });
      current.setMonth(current.getMonth() + 1);
    }
    
    return months;
  };

  const exportRoadmap = async (format: 'pdf' | 'excel' | 'image') => {
    if (!selectedClient) {
      alert('Please select a client first');
      return;
    }
    
    try {
      if (format === 'image') {
        // For image export, we'll create a canvas screenshot
        const roadmapElement = document.querySelector('.roadmap-grid');
        if (roadmapElement) {
          // Use html2canvas or similar library for image export
          console.log('Exporting roadmap as image');
          alert('Image export functionality would be implemented here with html2canvas');
        }
      } else {
        const result = await roadmapApi.exportRoadmap(format, selectedClient.id);
        console.log(`Exported roadmap as ${format}:`, result);
        alert(`Roadmap exported as ${format.toUpperCase()}`);
      }
    } catch (error) {
      console.error('Export failed:', error);
      alert('Export failed. Please try again.');
    }
  };

  const syncWithCMS = async () => {
    if (!selectedClient) {
      alert('Please select a client first');
      return;
    }
    
    try {
      const result = await roadmapApi.syncWithCMS(selectedClient.id);
      console.log('Sync result:', result);
      // Refresh assets after sync
      queryClient.invalidateQueries({ queryKey: ['roadmap-assets'] });
      alert('Successfully synced with Content Management System');
    } catch (error) {
      console.error('Sync failed:', error);
      alert('Sync failed. Please try again.');
    }
  };

  const [draggedAsset, setDraggedAsset] = useState<Asset | null>(null);

  // Drag and drop handlers
  const handleDragStart = (e: React.DragEvent, asset: Asset) => {
    setDraggedAsset(asset);
    e.dataTransfer.effectAllowed = 'move';
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
  };

  const handleDrop = (e: React.DragEvent, targetStage: FunnelStage) => {
    e.preventDefault();
    
    if (!draggedAsset) return;
    
    if (draggedAsset.funnelStage !== targetStage) {
      updateAssetMutation.mutate({
        id: draggedAsset.id,
        updates: { funnelStage: targetStage }
      });
    }
    
    setDraggedAsset(null);
  };

  const handleDragEnd = () => {
    setDraggedAsset(null);
  };

  const currentPeriod = getCurrentPeriod();
  const periodMonths = getMonthsForPeriod(currentPeriod);

  return (
    <div className="roadmap-generator">
      {!selectedClient ? (
        <div className="text-center py-12">
          <div className="w-16 h-16 mx-auto mb-4 bg-gray-100 rounded-full flex items-center justify-center">
            <Calendar className="w-8 h-8 text-gray-400" />
          </div>
          <h3 className="text-lg font-medium text-gray-900 mb-2">
            Client Selection Required
          </h3>
          <p className="text-gray-600">
            Please select a client to access the marketing roadmap generator.
          </p>
        </div>
      ) : (
        <>
          {/* Header Controls */}
          <div className="flex flex-wrap items-center justify-between mb-6 p-4 bg-gray-50 rounded-lg">
        <div className="flex items-center space-x-4">
          <h2 className="text-xl font-semibold text-gray-900">Marketing Roadmap</h2>
          <select
            value={selectedPeriod}
            onChange={(e) => setSelectedPeriod(e.target.value)}
            className="px-3 py-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
          >
            {periods.map(period => (
              <option key={period.id} value={period.id}>{period.name}</option>
            ))}
          </select>
        </div>
        
        <div className="flex items-center space-x-2">
          <button
            onClick={() => setZoomLevel(prev => Math.max(0.5, prev - 0.1))}
            className="px-3 py-2 bg-gray-200 hover:bg-gray-300 rounded-md text-sm"
          >
            Zoom Out
          </button>
          <span className="text-sm text-gray-600">{Math.round(zoomLevel * 100)}%</span>
          <button
            onClick={() => setZoomLevel(prev => Math.min(2, prev + 0.1))}
            className="px-3 py-2 bg-gray-200 hover:bg-gray-300 rounded-md text-sm"
          >
            Zoom In
          </button>
          
          <div className="border-l border-gray-300 pl-2 ml-2 flex space-x-2">
            <button
              onClick={syncWithCMS}
              className="inline-flex items-center px-3 py-2 bg-green-600 text-white rounded-md hover:bg-green-700 text-sm"
            >
              <RefreshCw className="w-4 h-4 mr-1" />
              Sync CMS
            </button>
            
            <div className="relative group">
              <button className="inline-flex items-center px-3 py-2 bg-blue-600 text-white rounded-md hover:bg-blue-700 text-sm">
                <Download className="w-4 h-4 mr-1" />
                Export
              </button>
              <div className="absolute top-full right-0 mt-1 w-32 bg-white border border-gray-300 rounded-md shadow-lg opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all z-10">
                <button
                  onClick={() => exportRoadmap('pdf')}
                  className="w-full text-left px-3 py-2 text-sm hover:bg-gray-100 flex items-center"
                >
                  <Download className="w-3 h-3 mr-2" />
                  PDF
                </button>
                <button
                  onClick={() => exportRoadmap('excel')}
                  className="w-full text-left px-3 py-2 text-sm hover:bg-gray-100 flex items-center"
                >
                  <FileSpreadsheet className="w-3 h-3 mr-2" />
                  Excel
                </button>
                <button
                  onClick={() => exportRoadmap('image')}
                  className="w-full text-left px-3 py-2 text-sm hover:bg-gray-100 flex items-center"
                >
                  <FileImage className="w-3 h-3 mr-2" />
                  Image
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Timeline Header */}
      <div className="mb-4">
        <div className="flex items-center justify-between mb-2">
          <h3 className="text-lg font-medium text-gray-900">{currentPeriod.name}</h3>
          <div className="flex items-center space-x-2">
            <button
              onClick={() => setCurrentMonth(prev => Math.max(0, prev - 1))}
              disabled={currentMonth === 0}
              className="p-1 rounded-md bg-gray-200 hover:bg-gray-300 disabled:opacity-50"
            >
              <ChevronLeft className="w-4 h-4" />
            </button>
            <span className="text-sm text-gray-600">
              {periodMonths[currentMonth]?.name} {periodMonths[currentMonth]?.year}
            </span>
            <button
              onClick={() => setCurrentMonth(prev => Math.min(periodMonths.length - 1, prev + 1))}
              disabled={currentMonth === periodMonths.length - 1}
              className="p-1 rounded-md bg-gray-200 hover:bg-gray-300 disabled:opacity-50"
            >
              <ChevronRight className="w-4 h-4" />
            </button>
          </div>
        </div>
        
        {/* Month Timeline */}
        <div className="flex space-x-1 overflow-x-auto pb-2">
          {periodMonths.map((month, index) => (
            <div
              key={index}
              className={`min-w-24 px-3 py-2 text-center text-sm rounded-md cursor-pointer ${
                index === currentMonth 
                  ? 'bg-blue-100 text-blue-800 border-2 border-blue-300' 
                  : 'bg-gray-100 text-gray-700 hover:bg-gray-200'
              }`}
              onClick={() => setCurrentMonth(index)}
            >
              {month.name}
            </div>
          ))}
        </div>
      </div>

      {/* Main Roadmap */}
      <div className="roadmap-grid" style={{ transform: `scale(${zoomLevel})`, transformOrigin: 'top left' }}>
        <div className="grid gap-6">
          {/* Campaign Headers */}
          <div className="flex space-x-4 mb-4">
            {campaigns.map(campaign => (
              <div
                key={campaign.id}
                className="flex-1 p-4 rounded-lg text-white font-semibold text-center"
                style={{ backgroundColor: campaign.color }}
              >
                {campaign.name}
              </div>
            ))}
          </div>
          
          {/* Information Banner */}
          <div className="mb-4 p-3 bg-blue-50 border border-blue-200 rounded-lg">
            <div className="flex items-center">
              <RefreshCw className="w-5 h-5 text-blue-500 mr-2" />
              <p className="text-sm text-blue-700">
                <strong>Content Integration:</strong> Assets displayed here are loaded from your Content Management system. 
                To add new assets, use the Content Management page. You can organize and schedule existing assets across funnel stages here.
              </p>
            </div>
          </div>

          {/* Funnel Stages */}
          {FUNNEL_STAGES.map(stage => (
            <div key={stage.id} className="funnel-stage">
              <div className="flex items-center mb-3">
                <div
                  className="px-4 py-2 rounded-lg text-white font-medium mr-4 min-w-32"
                  style={{ backgroundColor: stage.darkColor }}
                >
                  {stage.name}
                </div>
              </div>

              <div
                className="grid grid-cols-3 gap-4 min-h-24 p-4 rounded-lg border-2 border-dashed border-gray-300"
                style={{ backgroundColor: stage.color }}
                onDragOver={handleDragOver}
                onDrop={(e) => handleDrop(e, stage.id as FunnelStage)}
              >
                {getAssetsForStage(stage.id as FunnelStage).map((asset, index) => (
                  <div
                    key={asset.id}
                    draggable
                    onDragStart={(e) => handleDragStart(e, asset)}
                    onDragEnd={handleDragEnd}
                    className={`asset-box bg-white p-3 rounded-md shadow-sm border hover:shadow-md transition-shadow cursor-move ${
                      draggedAsset?.id === asset.id ? 'opacity-50' : ''
                    }`}
                  >
                    <div className="flex justify-between items-start mb-2">
                      <h4 className="font-medium text-sm text-gray-900 truncate">{asset.title}</h4>
                      <div className="flex space-x-1">
                        <button
                          onClick={(e) => {
                            e.stopPropagation();
                            startEditingAsset(asset);
                          }}
                          className="p-1 hover:bg-gray-100 rounded"
                        >
                          <Edit3 className="w-3 h-3 text-gray-500" />
                        </button>
                        <button
                          onClick={(e) => {
                            e.stopPropagation();
                            deleteAssetMutation.mutate(asset.id);
                          }}
                          className="p-1 hover:bg-gray-100 rounded"
                        >
                          <Trash2 className="w-3 h-3 text-red-500" />
                        </button>
                      </div>
                    </div>
                    <div className="text-xs text-gray-600 space-y-1">
                      <div>📅 {new Date(asset.dueDate).toLocaleDateString()}</div>
                      <div>📱 {asset.channel}</div>
                      <div className="inline-block px-2 py-1 bg-gray-100 rounded text-xs">
                        {campaigns.find(c => c.id === asset.campaign)?.name}
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Asset Form Modal */}
      {editingAsset && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
          <div className="bg-white p-6 rounded-lg w-full max-w-md">
            <div className="flex justify-between items-center mb-4">
              <h3 className="text-lg font-semibold">
                Edit Asset Schedule
              </h3>
              <button
                onClick={() => {
                  setEditingAsset(null);
                  resetAssetForm();
                }}
                className="p-1 hover:bg-gray-100 rounded"
              >
                <X className="w-5 h-5" />
              </button>
            </div>

            <form onSubmit={handleFormSubmit} className="space-y-4">
              {/* Show asset title as read-only */}
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Asset</label>
                <div className="w-full px-3 py-2 bg-gray-50 border border-gray-300 rounded-md text-gray-700">
                  {editingAsset?.title}
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Start Date</label>
                  <input
                    type="date"
                    value={assetForm.startDate}
                    onChange={(e) => setAssetForm(prev => ({ ...prev, startDate: e.target.value }))}
                    className="w-full px-3 py-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Due Date</label>
                  <input
                    type="date"
                    value={assetForm.dueDate}
                    onChange={(e) => setAssetForm(prev => ({ ...prev, dueDate: e.target.value }))}
                    className="w-full px-3 py-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                    required
                  />
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Channel</label>
                <select
                  value={assetForm.channel}
                  onChange={(e) => setAssetForm(prev => ({ ...prev, channel: e.target.value }))}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                  required
                >
                  <option value="">Select Channel</option>
                  <option value="Instagram">Instagram</option>
                  <option value="Facebook">Facebook</option>
                  <option value="TikTok">TikTok</option>
                  <option value="Email">Email</option>
                  <option value="Website">Website</option>
                  <option value="SMS">SMS</option>
                  <option value="YouTube">YouTube</option>
                </select>
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Funnel Stage</label>
                <select
                  value={assetForm.funnelStage}
                  onChange={(e) => setAssetForm(prev => ({ ...prev, funnelStage: e.target.value as FunnelStage }))}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                  required
                >
                  {FUNNEL_STAGES.map(stage => (
                    <option key={stage.id} value={stage.id}>{stage.name}</option>
                  ))}
                </select>
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Campaign</label>
                <select
                  value={assetForm.campaign}
                  onChange={(e) => setAssetForm(prev => ({ ...prev, campaign: e.target.value }))}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                  required
                >
                  {campaigns.map(campaign => (
                    <option key={campaign.id} value={campaign.id}>{campaign.name}</option>
                  ))}
                </select>
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Description</label>
                <textarea
                  value={assetForm.description}
                  onChange={(e) => setAssetForm(prev => ({ ...prev, description: e.target.value }))}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                  rows={3}
                />
              </div>

              <div className="flex space-x-4 pt-4">
                <button
                  type="submit"
                  disabled={updateAssetMutation.isPending}
                  className="flex-1 inline-flex items-center justify-center px-4 py-2 bg-blue-600 text-white rounded-md hover:bg-blue-700 disabled:opacity-50"
                >
                  <Save className="w-4 h-4 mr-2" />
                  Update Asset Schedule
                </button>
                <button
                  type="button"
                  onClick={() => {
                    setEditingAsset(null);
                    resetAssetForm();
                  }}
                  className="px-4 py-2 border border-gray-300 text-gray-700 rounded-md hover:bg-gray-50"
                >
                  Cancel
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* CSS Styles */}
      <style>{`
        .roadmap-generator {
          font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif;
        }
        
        .roadmap-grid {
          min-width: 100%;
          transition: transform 0.2s ease;
        }
        
        .funnel-stage {
          margin-bottom: 1.5rem;
        }
        
        .asset-box {
          min-height: 80px;
          transition: all 0.2s ease;
        }
        
        .asset-box:hover {
          transform: translateY(-1px);
        }
        
        @media (max-width: 768px) {
          .roadmap-grid {
            transform: scale(0.8) !important;
          }
          
          .grid-cols-3 {
            grid-template-columns: 1fr;
          }
        }
      `}</style>
        </>
      )}
    </div>
  );
};

export default RoadmapGenerator;
